#include <stdio.h>
#include <stdlib.h>

struct Kurs {
    char naziv[30];
    int sifra;
    int ects;
};

int main() {
    struct Kurs k;
    int n, i;

    FILE *f = fopen("kurs.dat", "wb");
    if (f == NULL) {
        printf("Greska pri otvaranju datoteke kurs.dat\n");
        return 1;
    }

    printf("Koliko kurseva zelite unijeti: ");
    scanf("%d", &n);

    for (i = 0; i < n; i++) {
        printf("\nKurs %d\n", i + 1);

        printf("Naziv kursa: ");
        scanf("%s", k.naziv);

        printf("Sifra kursa: ");
        scanf("%d", &k.sifra);

        printf("ECTS bodovi: ");
        scanf("%d", &k.ects);

        fwrite(&k, sizeof(struct Kurs), 1, f);
    }

    fclose(f);

    printf("Binarna datoteka kurs.dat je uspjesno kreirana.\n");

    return 0;
}
